import org.springframework.http.*;
import org.springframework.web.client.RestTemplate;
 
@RestController
public class WebHookHandler {
    private final RestTemplate restTemplate = new RestTemplate();
    
    @PostMapping("/processWebhook") // Assuming the '/' path of this API endpoint is set in your application properties or elsewhere for a specific use case.  
    public ResponseEntity<String> process(@RequestBody String url) { 
        HttpHeaders headers = new HttpHeaders();
	headers.setContentType(MediaType.APPLICATION_JSON); //You should define what to return here based on the data type of your webhook content - APPLICATION_XML,TEXT etc...  
		   
	// Fetching Data from URLs provided by users – Assuming you are passing only one url at a time in post request. Multiple urls can be passed too through array or list format below	     //For now assuming we're sending it as String type data       
	    HttpEntity<String> entity = new HttpEntity<>(url, headers);  
		 
	// Calling Web service using RestTemplate   
         ResponseEntity <String > response= restTemplate.exchange("http://"+ url ,HttpMethod.POST,entity,String.class);      //Add the URL in place of http:/.    
	    return response;       }  
}